function search(root, budget):
    for rollout in 1..budget:
        node = select(root)                # walk down by sampling
        action, model = sample_action(node) # Thompson draw
        child = expand(node, action, model)
        score = evaluate(child)             # verifier or oracle
        backpropagate(child, score)
    return best_leaf(root)

function sample_action(node):
    # actions: deepen current candidate, or branch fresh
    samples = {}
    for (action, model), posterior in node.posteriors.items():
        samples[(action, model)] = posterior.sample()
    return argmax(samples)                  # highest sampled value

function backpropagate(node, score):
    while node is not None:
        node.posteriors[node.taken_action].update(score)
        node = node.parent

SUCCESS, FAILURE, RUNNING = "S", "F", "R"

class AuditedNode:
    def __init__(self, name, child):
        self.name, self.child = name, child
        self.fail_streak = 0

    def tick(self, ctx):
        t0 = now()
        status = self.child.tick(ctx)
        # audit record per node tick: name, status, latency, ctx hash
        ctx.audit.append({
            "node":   self.name,
            "status": status,
            "ms":     now() - t0,
            "ctx":    ctx.fingerprint(),
        })
        if status == FAILURE:
            self.fail_streak += 1
            if self.fail_streak >= ctx.replan_threshold:
                ctx.signal_replan(self.name)       # subtree exhausted
        else:
            self.fail_streak = 0
        return status

class Timeout:
    def __init__(self, child, ms): self.child, self.ms = child, ms
    def tick(self, ctx):
        with deadline(self.ms):
            return self.child.tick(ctx)

ctx.step_budget = StepBudget(max_ticks=200)

while not ctx.done:
    if ctx.step_budget.exceeded():
        ctx.abort("step budget")
        break
    tree.tick(ctx)
    ctx.step_budget.increment()

# Why this works: every leaf and decorator writes a structured tick record,
# so a failing subtree is visible in the audit log rather than only as a
# top-level FAILURE. The step budget bounds run-away ticking and persistent
# subtree failure triggers a replan instead of grinding forever.
# Related: see `step-budget`, `replan-on-failure`, `behavior-tree-back-chaining`.

SUCCESS, FAILURE = "S", "F"

class CircuitBreaker:
    def __init__(self, threshold=3, cooldown_ms=30_000):
        self.failures, self.opened_at = 0, None
        self.threshold, self.cooldown_ms = threshold, cooldown_ms

    def allow(self):
        if self.opened_at is None: return True
        if now() - self.opened_at > self.cooldown_ms:
            self.opened_at = None; self.failures = 0   # half-open
            return True
        return False

    def record(self, ok):
        if ok: self.failures = 0
        else:
            self.failures += 1
            if self.failures >= self.threshold:
                self.opened_at = now()

class BreakeredLLMLeaf:
    def __init__(self, prompt, breaker):
        self.prompt, self.breaker = prompt, breaker
    def tick(self, ctx):
        if not self.breaker.allow():
            return FAILURE                           # skip; selector falls through
        out = llm.call(self.prompt, ctx)
        self.breaker.record(out.ok)
        return SUCCESS if out.ok else FAILURE

# The selector tries the primary leaf, then a fallback. When the primary's
# breaker opens, the selector cheaply falls through to the fallback for the
# cooldown window without paying the LLM call.
breaker = CircuitBreaker()
tree = Selector([
    BreakeredLLMLeaf("primary_answer", breaker),
    LLMLeaf("fallback_answer"),
])

# Why this works: the BT's selector semantics already encode "try-then-
# fallback"; the breaker makes that fallback fast once the primary is
# consistently broken. Audit recovery happens automatically when the
# cooldown ends.
# Related: see `circuit-breaker`, `fallback-chain`, `agentic-behavior-tree`.

# A library of known tasks, each with pre/post conditions.
TASKS = [
    Task("reserve_venue", pre={"budget_ok"},     post={"venue_reserved"}),
    Task("check_budget",  pre=set(),               post={"budget_ok"}),
    Task("send_invites",  pre={"venue_reserved"}, post={"invites_sent"}),
]

def back_chain(goal_condition, state, depth=0):
    if goal_condition.issubset(state):
        return Leaf("already_satisfied")
    if depth > MAX_DEPTH:
        return Leaf("give_up")

    # Find tasks whose post-conditions cover (some of) the goal.
    producers = [t for t in TASKS if t.post & goal_condition]
    if not producers:
        return Leaf("no_producer_for_" + str(goal_condition))

    # For each producer: build a Sequence(satisfy-its-pre, run-task).
    branches = []
    for t in producers:
        sub_goal = t.pre - state              # what still needs producing
        child    = back_chain(sub_goal, state, depth + 1)
        branches.append(Sequence([child, Run(t)]))

    # Selector: try producers left-to-right, succeed on first that works.
    return Selector(branches)

# Author the whole tree from the desired goal condition downward.
tree = back_chain(goal_condition={"invites_sent"}, state={"have_guest_list"})
prune_to_realistic_cases(tree)

# Why this works: every node exists because it produces a precondition its
# parent needs, not because the designer thought of it. The discipline
# yields trees that are principled rather than decorative.
# Related: see `agentic-behavior-tree`, `goal-decomposition`.

MAX_DEPTH = 8
MAX_NODES = 200

def back_chain_prod(goal, state, depth=0, visiting=None, audit=None):
    visiting = visiting or set()
    audit    = audit    or AuditLog()

    if goal.issubset(state):
        audit.record("satisfied", goal, depth)
        return Leaf("already_satisfied")
    if depth > MAX_DEPTH or audit.node_count() > MAX_NODES:
        audit.record("budget_exhausted", goal, depth)
        return Leaf("budget_exhausted")
    if frozenset(goal) in visiting:               # cycle guard
        audit.record("cycle_detected", goal, depth)
        return Leaf("cycle")

    producers = [t for t in TASKS if t.post & goal]
    if not producers:
        audit.record("no_producer", goal, depth)
        signal_replan(goal)                        # caller may extend TASKS
        return Leaf("no_producer")

    visiting = visiting | {frozenset(goal)}
    branches = []
    for t in producers:
        sub_goal = t.pre - state
        child    = back_chain_prod(sub_goal, state, depth+1, visiting, audit)
        audit.record("producer_used", t.name, depth)
        branches.append(Sequence([child, Run(t)]))

    return Selector(branches)

tree = back_chain_prod(goal={"shipped"}, state=current_state())
prune_to_realistic_cases(tree)

# Why this works: every node added is justified in the audit as "producer
# X satisfies condition Y"; cycles and depth blow-ups become explicit
# records rather than infinite recursion. Missing-producer is a signal to
# the human to extend the task library, not a silent gap.
# Related: see `agentic-behavior-tree`, `replan-on-failure`.

function clone_fan_out_prod(goal, N, total_budget):
    slices = partition(goal, N)
    per_clone_budget = total_budget / N
    if total_budget > GLOBAL_CAP: abort("budget cap")

    sandboxes = [allocate_sandbox(isolation="strict") for _ in range(N)]
    audit = AuditLog()
    results = []

    def run_one(slice, sb, idx):
        t0 = now()
        try:
            agent = Agent(
                system_prompt = SAME_PROMPT,
                tools         = FULL_TOOLSET,
                sandbox       = sb,
                budget        = per_clone_budget,
            )
            r = agent.run(slice)
            assert sb.is_isolated(), "sandbox leak"
            audit.record(idx, ok=True, ms=now()-t0, cost=agent.cost)
            return Outcome(idx=idx, ok=True, value=r)
        except (Timeout, SandboxLeak, ToolError) as e:
            audit.record(idx, ok=False, ms=now()-t0, err=str(e))
            return Outcome(idx=idx, ok=False, err=str(e))
        finally:
            sb.destroy()

    results = parallel_for(slices, sandboxes, range(N), fn=run_one)

    successes = [r for r in results if r.ok]
    if len(successes) < N * MIN_SUCCESS_RATIO:
        return Result(ok=False, reason="too few successes", audit=audit)

    return aggregator.run(
        goal, successes,
        strategy = "vote|rank|dedupe|synthesise",
        audit    = audit,
    )

# Why this works: each clone writes a row to the audit log so cost and
# failure are accounted per slice; sandbox isolation is asserted rather
# than assumed; partial results tolerate clone failure up to a declared
# success ratio.
# Related: see `subagent-isolation`, `step-budget`, `parallelization`.

# Typed signals the LLM is allowed to emit. NEVER "choose your next branch".
INTENT = Enum("REFUND", "REPLACE", "ESCALATE", "REJECT")

def classify_intent(message) -> INTENT:
    return llm.classify(
        input  = message,
        schema = INTENT,                # typed, validated, retried-on-parse-fail
    )

def score_risk(message) -> float:       # 0.0 .. 1.0
    return llm.score(input=message, schema=FloatRange(0, 1))

# Deterministic control flow: the if/else lives here, not in any prompt.
def handle(message):
    intent = classify_intent(message)
    risk   = score_risk(message)

    if risk > 0.8:
        return route_to("human_queue", message)

    if intent == INTENT.REFUND:
        return refund_workflow.run(message)
    if intent == INTENT.REPLACE:
        return replacement_workflow.run(message)
    if intent == INTENT.ESCALATE:
        return route_to("human_queue", message)
    if intent == INTENT.REJECT:
        return polite_decline(message)

    raise UnreachableBranch(intent)      # enum exhaustiveness is checkable

# Why this works: every branch is enumerable and testable; the LLM cannot
# invent a fifth path or skip risk-scoring. Debugging reads code, not
# prompt traces.
# Related: see `structured-output`, `json-only-action-schema`.

INTENT = Enum("REFUND", "REPLACE", "ESCALATE", "REJECT")

def call_with_validation(fn, schema, *, retries=2):
    audit = []
    for attempt in range(retries + 1):
        t0 = now()
        raw = fn()
        ok, parsed_or_err = schema.validate(raw)
        audit.append({"attempt": attempt, "ok": ok, "ms": now()-t0})
        if ok:
            return parsed_or_err, audit
    raise SignalUnparseable(schema, audit)         # never silently coerce

def classify_intent(message):
    return call_with_validation(
        lambda: llm.classify(input=message, schema=INTENT),
        schema=INTENT,
    )

def score_risk(message):
    return call_with_validation(
        lambda: llm.score(input=message, schema=FloatRange(0, 1)),
        schema=FloatRange(0, 1),
    )

def handle_prod(message, audit_log):
    intent, ia = classify_intent(message)
    risk,   ra = score_risk(message)
    audit_log.write({"msg_id": message.id, "intent": intent,
                     "risk": risk, "intent_audit": ia, "risk_audit": ra})

    if risk > 0.8:                       return route_to("human_queue", message)
    if intent == INTENT.REFUND:          return refund_workflow.run(message)
    if intent == INTENT.REPLACE:         return replacement_workflow.run(message)
    if intent == INTENT.ESCALATE:        return route_to("human_queue", message)
    if intent == INTENT.REJECT:          return polite_decline(message)

    # Enum exhaustiveness: build-time check ensures every variant is handled.
    assert_exhaustive(INTENT, intent)

# Why this works: parse-fail retries are bounded and audited rather than
# silent coercion; per-message audit records every branch chosen; enum
# exhaustiveness is a compile-time check so adding a fifth intent fails
# the build instead of silently falling through.
# Related: see `structured-output`, `step-budget`, `json-only-action-schema`.

# The LLM emits a typed JSON action; the dispatcher branches on action_type.
# The LLM never picks the next branch; it picks the next ACTION.

ACTION_SCHEMA = {
    "type": "object",
    "required": ["action_type", "payload"],
    "properties": {
        "action_type": {"enum": ["refund", "replace", "escalate", "reject"]},
        "payload":     {"type": "object"},
    },
}

def next_action(message, history):
    raw = llm.generate(
        prompt          = ROUTING_PROMPT,
        input           = {"message": message, "history": history},
        response_format = {"type": "json_schema", "schema": ACTION_SCHEMA},
    )
    return validate(raw, ACTION_SCHEMA)

# Deterministic dispatcher: every branch is enumerable, testable, and
# debuggable from CODE, not from prompt traces.
DISPATCH = {
    "refund":   refund_workflow.run,
    "replace":  replacement_workflow.run,
    "escalate": lambda m: route_to("human_queue", m),
    "reject":   polite_decline,
}

def handle(message, history):
    action = next_action(message, history)
    fn = DISPATCH[action["action_type"]]       # KeyError = unknown action
    return fn(message, **action["payload"])

# Why this works: json-only-action-schema constrains what the LLM can emit;
# deterministic-control-flow guarantees the if/else lives in code. Together,
# every branch is enumerable, every action is typed, and the LLM cannot
# invent an action_type the dispatcher does not know about.
# Related: see `json-only-action-schema`, `structured-output`.

# DCOP: each agent owns a variable; constraints are factored across pairs.
class Agent:
    def __init__(self, var, domain, neighbours):
        self.var        = var
        self.domain     = domain
        self.neighbours = neighbours   # only these see our value
        self.value      = pick_initial(domain)
        self.nb_values  = {}           # latest known value per neighbour

    def on_message(self, sender, value):
        self.nb_values[sender] = value
        self.maybe_improve()

    def local_cost(self, candidate):
        return sum(constraint_cost(self.var, candidate, n, v)
                   for n, v in self.nb_values.items())

    def maybe_improve(self):
        # Local search step (Max-Sum / DSA family).
        best = min(self.domain, key=self.local_cost)
        if best != self.value:
            self.value = best
            for n in self.neighbours:
                send(n, self.var, self.value)   # only neighbours, only deltas

# Driver: kick off, then let the message passing run until quiescent.
for a in agents: a.maybe_improve()
run_until_no_messages_for(QUIESCENCE_WINDOW)

# For LLM-agent applications: replace `pick_initial` and the candidate
# scoring with an LLM propose-and-evaluate step at each agent; the DCOP
# backbone keeps global consistency without centralising private state.

# Why this works: no agent ever sees the whole problem; messages are bounded
# to constraint-neighbours; the algorithm terminates with each agent holding
# a value consistent with its neighbours and approximately globally optimal.
# Related: see `partial-global-planning`, `contract-net-protocol`.

class AgentProd:
    def __init__(self, var, domain, neighbours, msg_budget, audit):
        self.var, self.domain, self.neighbours = var, domain, neighbours
        self.value = pick_initial(domain)
        self.nb_values = {}
        self.msg_budget, self.audit = msg_budget, audit
        self.last_improve_round = 0
        self.round = 0

    def step(self):
        self.round += 1
        best = min(self.domain, key=self.local_cost)
        if best != self.value:
            self.value = best
            self.last_improve_round = self.round
            for n in self.neighbours:
                if self.msg_budget.allow(n):
                    send(n, self.var, self.value)
                    self.audit.message(self.var, n)
                else:
                    self.audit.dropped(self.var, n, reason="budget")

    def stuck(self, k=10):
        return self.round - self.last_improve_round > k

for a in agents:
    a.step()
while not quiescent(agents) and now() < deadline:
    process_one_message()
    if all(a.stuck() for a in agents):
        signal_replan("all agents stuck; possibly infeasible")
        break

# Why this works: message budgets prevent neighbour-flooding; quiescence
# detection is explicit rather than "run for N rounds"; the audit records
# per-edge traffic so a bottleneck pair is visible. Universal-stuck is a
# replan signal, not silent low-quality termination.
# Related: see `step-budget`, `replan-on-failure`, `partial-global-planning`.

# Contract-net assigns WHICH agent owns which task; DCOP then negotiates
# the SHARED-VARIABLE values across assigned tasks subject to constraints.

# Stage 1: Contract-net assignment.
def assign_tasks(tasks):
    assignments = {}
    for task in tasks:
        announce(task)
        bids = collect_bids(task, timeout=BID_WINDOW)
        winner = pick_lowest_cost_bid(bids)
        award(winner, task)
        assignments[task.id] = winner
    return assignments

# Stage 2: DCOP over the shared variables INSIDE assigned tasks.
def refine_via_dcop(assignments, shared_vars):
    # Each assigned agent owns its task's parameters as DCOP variables.
    dcop_agents = []
    for task_id, agent in assignments.items():
        for v in shared_vars[task_id]:
            dcop_agents.append(DcopAgent(
                owner      = agent,
                var        = v,
                domain     = v.domain,
                neighbours = constraint_neighbours_of(v, assignments),
            ))
    run_until_quiescent(dcop_agents)
    return {a.var: a.value for a in dcop_agents}

assignments = assign_tasks(global_tasks)
values = refine_via_dcop(assignments, shared_variables)

# Why this works: contract-net decides WHO; DCOP decides WHAT VALUES. Each
# pattern solves a different layer of coordination: assignment is a market;
# parameter optimisation is constraint negotiation. Composing them lets the
# team avoid centralising either decision.
# Related: see `contract-net-protocol`, `partial-global-planning`.

subscribe(event_source) do |event|
    if not validate(event):
        reject(event); continue
    if seen_recently(event.id):       # idempotency / dedupe
        ack(event); continue
    if rate_limited():
        defer(event); continue

    try:
        result = agent.run(event.payload)
        record(event.id, result)
        ack(event)                     # ack only on success
    except Exception as exc:
        nack(event, reason=exc)        # let the source redeliver

import asyncio
from workflows import Workflow, step
from workflows.events import Event, StartEvent, StopEvent
from llama_index.llms.openai import OpenAI


class WebhookEvent(Event):
    payload: dict


class AgentReplyEvent(Event):
    text: str


class WebhookAgentFlow(Workflow):
    llm = OpenAI(model="gpt-4o-mini")

    @step
    async def receive(self, ev: StartEvent) -> WebhookEvent:
        # In production: validate signature, dedupe by ev.delivery_id.
        return WebhookEvent(payload=ev.payload)

    @step
    async def run_agent(self, ev: WebhookEvent) -> AgentReplyEvent:
        prompt = f"Triage this webhook payload: {ev.payload}"
        response = await self.llm.acomplete(prompt)
        return AgentReplyEvent(text=str(response))

    @step
    async def finish(self, ev: AgentReplyEvent) -> StopEvent:
        return StopEvent(result=ev.text)


async def main():
    flow = WebhookAgentFlow(timeout=60)
    result = await flow.run(payload={"action": "opened", "pr": 42})
    print(result)


asyncio.run(main())

from dataclasses import dataclass
from datetime import timedelta
from temporalio import workflow


@dataclass
class WebhookEvent:
    delivery_id: str
    payload: dict


@workflow.defn
class EventDrivenAgent:
    def __init__(self) -> None:
        self._inbox: list[WebhookEvent] = []
        self._seen: set[str] = set()

    @workflow.signal
    def deliver(self, event: WebhookEvent) -> None:
        # Idempotency: drop duplicate deliveries.
        if event.delivery_id in self._seen:
            return
        self._seen.add(event.delivery_id)
        self._inbox.append(event)

    @workflow.run
    async def run(self) -> None:
        while True:
            await workflow.wait_condition(lambda: bool(self._inbox))
            event = self._inbox.pop(0)
            # Each event triggers one agent activity invocation.
            await workflow.execute_activity(
                "run_agent_once",
                event.payload,
                start_to_close_timeout=timedelta(minutes=5),
            )

function pick_action(actions, stats, strategy="thompson"):
    if strategy == "epsilon_greedy":
        if random() < EPSILON:
            return random_choice(actions)   # explore
        return argmax(actions, key=stats.mean)  # exploit

    if strategy == "ucb":
        t = total_pulls(stats)
        return argmax(actions, key=lambda a:
            stats[a].mean + sqrt(2 * log(t) / stats[a].pulls))

    if strategy == "thompson":
        # sample from each action's posterior, take the highest
        return argmax(actions, key=lambda a: stats[a].posterior.sample())

function loop():
    while running:
        a = pick_action(ACTIONS, STATS, strategy="thompson")
        reward = run(a)
        STATS[a].update(reward)             # refine posterior

class ArmStats:
    def __init__(self): self.window = deque(maxlen=200)   # recent rewards only
    def update(self, r): self.window.append(r)
    @property
    def n(self):    return len(self.window)
    @property
    def mean(self): return sum(self.window)/max(self.n,1)

def ucb_pick(arms, stats, t, audit):
    cold = [a for a in arms if stats[a].n < MIN_PULLS]
    if cold:
        choice = random_choice(cold)               # force minimum pulls
        audit.record(t, choice, "cold_start")
        return choice
    score = lambda a: stats[a].mean + sqrt(2 * log(t) / stats[a].n)
    choice = argmax(arms, key=score)
    audit.record(t, choice, f"ucb={score(choice):.3f}")
    return choice

def bandit_loop(arms, audit, budget):
    stats = {a: ArmStats() for a in arms}
    for t in range(1, budget+1):
        a = ucb_pick(arms, stats, t, audit)
        r = run(a)
        stats[a].update(r)

        # Replan trigger: if every arm's recent mean is under the floor,
        # the action set is wrong — escalate to operator.
        if t % AUDIT_INTERVAL == 0:
            if all(stats[a].mean < REWARD_FLOOR for a in arms):
                signal_replan("all arms below reward floor", stats)
                return Result(ok=False, audit=audit)
    return Result(ok=True, best=argmax(arms, key=lambda a: stats[a].mean))

# Why this works: windowed rewards adapt to non-stationary environments;
# MIN_PULLS prevents UCB from locking on after a single lucky pull; the
# audit lets post-hoc analysis see why each pull happened. Universal-floor
# failure is a replan signal rather than silent low performance.
# Related: see `bayesian-bandit-experimentation`, `step-budget`.

# A skill-library accumulates reusable skills; exploration-exploitation
# decides which skill to try when several apply, and which to retire.

class SkillLibrary:
    def __init__(self):
        self.skills = {}                           # name -> Skill
        self.stats  = {}                           # name -> ArmStats

    def applicable(self, task):
        return [name for name, s in self.skills.items() if s.matches(task)]

    def pick(self, task, strategy="thompson"):
        arms = self.applicable(task)
        if not arms:
            return None                            # caller falls back
        if strategy == "thompson":
            return argmax(arms, key=lambda a: self.stats[a].posterior.sample())
        if strategy == "epsilon_greedy":
            if random() < EPSILON:
                return random_choice(arms)
            return argmax(arms, key=lambda a: self.stats[a].mean)

    def record(self, name, reward):
        self.stats[name].update(reward)
        if self.stats[name].n > MIN_PULLS \
           and self.stats[name].mean < RETIRE_THRESHOLD:
            del self.skills[name]                  # prune the loser

# Run loop: pick a skill, run it, score by success, update the bandit.
lib = SkillLibrary()
for task in incoming:
    name = lib.pick(task, strategy="thompson")
    if name is None:
        result = fallback_solve(task)
        lib.add(synthesise_skill_from(result))     # grow the library
        continue
    result = lib.skills[name].run(task)
    lib.record(name, reward=score(result))

# Why this works: the library grows over time; the bandit ensures new skills
# get tried (cold-start), well-performing skills win their slots, and skills
# that consistently fail are retired without manual curation.
# Related: see `skill-library`, `bayesian-bandit-experimentation`.

function decompose(goal, depth=0):
    if depth > MAX_DEPTH or is_actionable(goal):
        return Leaf(goal)

    children = llm.split(goal)              # one level of decomposition
    if len(children) == 1 and children[0] == goal:
        return Leaf(goal)                   # cannot split further

    return Node(goal, [decompose(c, depth + 1) for c in children])

function execute(node):
    if node is Leaf:
        return run_action(node.goal)

    # siblings can run in parallel (distinct from least-to-most)
    results = parallel_for(node.children) do |child|
        return execute(child)
    end
    if any_stuck(results):
        surface_to_planner(node, results)   # observable per branch
    return combine(node.goal, results)

MAX_DEPTH      = 5
MAX_LEAVES     = 32
BRANCH_BUDGET  = StepBudget(steps=20)

def decompose_prod(goal, depth=0, audit=None):
    audit = audit or AuditLog()
    audit.record("decompose", goal, depth)
    if depth >= MAX_DEPTH or is_actionable(goal):
        return Leaf(goal)
    children = llm.split(goal)
    if not children or children == [goal]:
        return Leaf(goal)
    return Node(goal, [decompose_prod(c, depth+1, audit) for c in children])

def execute_prod(node, audit):
    if isinstance(node, Leaf):
        with BRANCH_BUDGET:
            t0 = now()
            try:
                r = run_action(node.goal)
                audit.record("leaf_ok", node.goal, ms=now()-t0)
                return Outcome(ok=True, value=r)
            except IrrecoverableError as e:
                audit.record("leaf_fail", node.goal, err=str(e))
                return Outcome(ok=False, err=str(e))

    results = parallel_for(node.children) do |child|
        return execute_prod(child, audit)
    end

    failed = [r for r in results if not r.ok]
    if failed:
        # Replan: walk up and ask the parent for a new decomposition.
        audit.record("sibling_failure", node.goal, failed)
        new_children = llm.replan_children(node.goal, failed)
        return execute_prod(Node(node.goal,
                                 [decompose_prod(c) for c in new_children]),
                            audit)
    return combine(node.goal, [r.value for r in results])

# Why this works: each leaf runs under a step budget so a single stuck
# branch cannot exhaust the global budget; sibling failure triggers a
# narrowly-scoped replan at the parent instead of a global restart.
# Related: see `step-budget`, `replan-on-failure`, `hierarchical-agents`.

# goal-decomposition produces a tree of goals; hierarchical-agents assigns
# one agent per non-leaf node, each running its own ReAct-style loop.

class NodeAgent:
    def __init__(self, goal, parent=None):
        self.goal, self.parent, self.children = goal, parent, []

    def run(self):
        if is_actionable(self.goal):
            return run_leaf_action(self.goal)

        sub_goals = self.llm_split(self.goal)
        self.children = [NodeAgent(sg, parent=self) for sg in sub_goals]

        # Children run in parallel; each is its own agent with its own loop.
        results = parallel_for(self.children) do |child|
            return child.run()
        end

        # Parent agent composes its children's outputs and reports up.
        composed = self.llm_compose(self.goal, results)
        if self.parent is not None:
            self.parent.notify_child_done(self, composed)
        return composed

    def llm_split(self, goal):
        return llm.split(goal, role=f"node-agent for {goal}")

    def llm_compose(self, goal, results):
        return llm.compose(goal, results, role=f"node-agent for {goal}")

root = NodeAgent(user_goal)
final = root.run()

# Why this works: each node is an agent with its own context window, so
# decomposition scales beyond what one agent can hold. The tree gives
# explicit structure; the hierarchical agents give per-node autonomy and
# per-node attribution when a sub-tree fails.
# Related: see `hierarchical-agents`, `plan-and-execute`.

# HTN interior nodes are deterministic; some interior nodes branch on a
# typed signal an LLM leaf emits — which is exactly deterministic-control-
# flow-not-prompt at the seam.

SEVERITY = Enum("LOW", "MEDIUM", "HIGH")

class ClassifyLeaf:                                   # generative leaf
    def run(self, ctx):
        return llm.classify(input=ctx.ticket, schema=SEVERITY)

class BranchOnSeverity:                               # deterministic node
    def __init__(self, low, medium, high):
        self.low, self.medium, self.high = low, medium, high
    def run(self, ctx):
        sev = ctx.get("severity")                     # set by ClassifyLeaf
        if sev == SEVERITY.LOW:    return self.low.run(ctx)
        if sev == SEVERITY.MEDIUM: return self.medium.run(ctx)
        if sev == SEVERITY.HIGH:   return self.high.run(ctx)
        assert_exhaustive(SEVERITY, sev)

# Compose the HTN. Branching is in CODE; the LLM emits a typed signal.
plan = Compound("triage_ticket", [
    Primitive(load_ticket, name="load"),
    BindResult("severity", ClassifyLeaf()),           # LLM -> typed enum
    BranchOnSeverity(
        low    = Compound("auto_close", [...]),       # deterministic path
        medium = Compound("queue",      [...]),       # deterministic path
        high   = Compound("page_oncall",[...]),       # deterministic path
    ),
])

# Why this works: the HTN gives structure for the known parts; the LLM is
# bounded to producing TYPED SIGNALS the deterministic branches consume.
# Neither the LLM nor the HTN can invent a fourth severity branch.
# Related: see `deterministic-control-flow-not-prompt`, `structured-output`.

def incremental_plan(goal, max_steps=20, budget=None):
    history     = []     # list of (step, observation) so far
    observation = initial_observation(goal)

    for i in range(max_steps):
        if budget and budget.exhausted():
            return abort("budget exhausted")

        # Ask ONLY for the next step, given everything seen so far.
        next_step = llm.next_step(
            goal        = goal,
            history     = history,
            observation = observation,
            schema      = STEP_SCHEMA,
        )

        if next_step.is_goal_met():
            return Result(ok=True, history=history)

        observation = executor.run(next_step)
        history.append((next_step, observation))

    return Result(ok=False, history=history, reason="step budget")

# Distinct from one-shot planning (whole plan in one call) and from
# multi-path generation (which yields K candidates per node).

# Why this works: each step is produced with full knowledge of the
# previous step's actual outcome, so the plan adapts to what really
# happened instead of what the model guessed would happen at step 0.
# Related: see `single-path-plan-generator`, `react`.

def incremental_plan_prod(goal, budget):
    history     = []
    observation = initial_observation(goal)
    audit       = AuditLog()
    last_ctx_fp = ctx_fingerprint(observation)

    for i in range(budget.max_steps):
        if budget.tokens_used > budget.tokens_cap:
            audit.record("abort", reason="token cap")
            return Result(ok=False, audit=audit)

        # Context-shift guard: if the world has drifted, force a re-ground.
        if drift(ctx_fingerprint(observation), last_ctx_fp) > DRIFT_THRESHOLD:
            observation = re_ground(observation)
            audit.record("re_ground", step=i)
            last_ctx_fp = ctx_fingerprint(observation)

        t0 = now()
        next_step = llm.next_step(
            goal        = goal,
            history     = history,
            observation = observation,
            schema      = STEP_SCHEMA,
        )
        audit.record("step", i, next_step, ms=now()-t0)

        if next_step.is_goal_met():
            return Result(ok=True, history=history, audit=audit)

        try:
            observation = executor.run(next_step)
            history.append((next_step, observation))
        except ToolError as e:
            audit.record("tool_error", i, err=str(e))
            signal_replan(goal, history, e)         # caller may restart
            return Result(ok=False, audit=audit)

    audit.record("abort", reason="step budget")
    return Result(ok=False, audit=audit)

# Why this works: each step is bounded by token cap AND step count; the
# context-shift guard forces re-grounding when the world moves under the
# plan; tool errors short-circuit to a replan instead of letting the next
# step compound the failure.
# Related: see `step-budget`, `replan-on-failure`, `react`.

node IterationNode:
    inputs:
        items: Array<T>
        concurrency: int = 1               # 1 = sequential
    subgraph: Subgraph(param: T -> result: R)
    outputs:
        results: Array<{index: int, ok: bool, value?: R, error?: str}>

function run(node, items):
    results = []
    pool = ConcurrencyPool(node.concurrency)
    for (i, item) in enumerate(items):
        pool.submit(i, () => {
            try:
                value = node.subgraph.run(param=item)
                emit_log(node, i, "ok")
                return {index: i, ok: true, value: value}
            except Exception as e:
                emit_log(node, i, "error", e)
                # failure scoped per element, node continues
                return {index: i, ok: false, error: str(e)}
        })
    return pool.collect_sorted_by_index()

node IterationNodeProd:
    inputs:
        items: Array<T>
        concurrency: int = 4
        per_item_timeout_ms: int = 30000
        per_item_retries: int = 2
        total_budget_ms: int = 600000
    subgraph: Subgraph(param: T -> result: R)
    outputs:
        results: Array<{index: int, ok: bool, value?: R, error?: str, attempts: int}>

function run(node, items):
    audit = AuditLog()
    results = []
    pool = AdaptiveConcurrencyPool(node.concurrency)
    deadline = now() + node.total_budget_ms

    for (i, item) in enumerate(items):
        if now() > deadline:
            audit.record(i, "skipped_budget")
            results.append({index: i, ok: false, error: "budget exhausted", attempts: 0})
            continue

        pool.submit(i, () => {
            for attempt in 1..node.per_item_retries+1:
                t0 = now()
                try:
                    value = with_timeout(node.per_item_timeout_ms,
                                         () => node.subgraph.run(param=item))
                    audit.record(i, "ok", attempt=attempt, ms=now()-t0)
                    return {index: i, ok: true, value: value, attempts: attempt}
                except Timeout as t:
                    audit.record(i, "timeout", attempt=attempt)
                except Exception as e:
                    audit.record(i, "error", attempt=attempt, err=str(e))
            # If error rate climbs, throttle the pool down.
            if pool.recent_error_rate() > ERROR_THROTTLE:
                pool.shrink()
            return {index: i, ok: false, error: "max retries", attempts: node.per_item_retries+1}
        })

    return pool.collect_sorted_by_index()

# Why this works: per-element timeout and retry contain transient failures;
# the audit log keeps a row per element so a flaky 47th item is locatable;
# adaptive concurrency backs off when error rate climbs, preventing the
# whole batch from melting upstream services.
# Related: see `step-budget`, `circuit-breaker`, `parallelization`.

function lats(root, budget):
    for iteration in 1..budget:
        leaf = select(root)                 # walk down by UCT
        children = expand(leaf)             # sample next thoughts/actions
        if not children:
            backpropagate(leaf, value(leaf))
            continue
        child = pick_unvisited(children)
        v = simulate(child)                 # rollout under value function
        backpropagate(child, v)
    return best_trajectory(root)

function select(node):
    while node.children and all_visited(node.children):
        node = argmax(node.children, key=uct_score)
    return node

function backpropagate(node, value):
    while node is not None:
        node.visits += 1
        node.total_value += value           # later: backtrack from low value
        node = node.parent

function llm_compiler(query):
    dag = planner.build(query)              # nodes with explicit deps
    results = {}
    pending = {n.id: set(n.deps) for n in dag.nodes}
    pool = ConcurrencyPool(MAX_PARALLEL)

    while pending or pool.in_flight():
        # task-fetching: dispatch any node whose deps are now resolved
        for n in dag.nodes:
            if n.id in pending and not pending[n.id]:
                pool.submit(n.id, () => run_tool(n, results))
                del pending[n.id]

        done_id, value = pool.wait_one()
        results[done_id] = value
        for nid in pending:
            pending[nid].discard(done_id)   # unblock downstream

    return joiner.assemble(query, dag, results)

function llm_compiler_prod(query, budget):
    audit = AuditLog()
    dag = planner.build(query)
    audit.record_plan(dag)

    results = {}
    pending = {n.id: set(n.deps) for n in dag.nodes}
    pool = ConcurrencyPool(min(MAX_PARALLEL, budget.parallelism))
    failures = 0

    deadline = now() + budget.total_ms

    while (pending or pool.in_flight()) and now() < deadline:
        for n in dag.nodes:
            if n.id in pending and not pending[n.id]:
                pool.submit(n.id, () => {
                    t0 = now()
                    for attempt in 1..PER_NODE_RETRIES+1:
                        try:
                            r = with_timeout(PER_NODE_TIMEOUT,
                                             () => run_tool(n, results))
                            audit.record(n.id, ok=True, attempt=attempt,
                                         ms=now()-t0)
                            return Ok(r)
                        except (Timeout, ToolError) as e:
                            audit.record(n.id, ok=False, attempt=attempt,
                                         err=str(e))
                    return Fail("max retries")
                })
                del pending[n.id]

        done_id, value = pool.wait_one()
        if isinstance(value, Fail):
            failures += 1
            if failures > len(dag.nodes) * MAX_FAIL_RATIO:
                # Replan: rebuild the DAG given what we now know.
                dag = planner.build(query, prior_results=results, failures=failures)
                pending = {n.id: set(n.deps) for n in dag.nodes if n.id not in results}
                continue
            results[done_id] = MissingValue(done_id)
        else:
            results[done_id] = value.unwrap()
        for nid in pending:
            pending[nid].discard(done_id)

    return joiner.assemble(query, dag, results, audit=audit)

# Why this works: per-node retries with timeouts contain transient tool
# failures; the audit makes each DAG node's history inspectable; high
# failure rates trigger a fresh plan instead of joining over too many gaps.
# Related: see `step-budget`, `replan-on-failure`, `parallel-tool-calls`.

# LLMCompiler dispatches DAG tasks concurrently; subagent-isolation gives
# each task its own sandbox so cross-task contamination is structurally
# impossible. The seam is the dispatcher allocating one sandbox per node.

function llm_compiler_isolated(query):
    dag = planner.build(query)
    results = {}
    pending = {n.id: set(n.deps) for n in dag.nodes}
    pool = ConcurrencyPool(MAX_PARALLEL)

    while pending or pool.in_flight():
        for n in dag.nodes:
            if n.id in pending and not pending[n.id]:
                # ONE sandbox per DAG node; destroyed on completion.
                sb = allocate_sandbox(isolation="strict", caps=n.required_caps)
                pool.submit(n.id, () => {
                    try:
                        sub = SubAgent(
                            tools     = n.allowed_tools,    # least-privilege
                            sandbox   = sb,
                            inputs    = substitute(n.args, results),
                        )
                        return sub.run_and_return_structured()
                    finally:
                        sb.destroy()                         # no leak across nodes
                })
                del pending[n.id]

        done_id, value = pool.wait_one()
        # Returned value is STRUCTURED, not arbitrary text — joiner consumes it.
        results[done_id] = value
        for nid in pending:
            pending[nid].discard(done_id)

    return joiner.assemble(query, dag, results)

# Why this works: tool results from one DAG node cannot leak into the
# prompt context of another; if one node is compromised (poisoned web
# page, prompt-injected document) the contamination stays in that node's
# sandbox. The DAG concurrency benefit is preserved.
# Related: see `subagent-isolation`, `rewoo`, `parallel-tool-calls`.

function map_reduce_prod(task, input, chunk_size, budget):
    audit = AuditLog()
    chunks = split(input, chunk_size)
    deadline = now() + budget.total_ms

    def map_one(chunk, idx):
        for attempt in range(MAP_RETRIES + 1):
            t0 = now()
            try:
                r = llm.map(
                    task=task, chunk=chunk,
                    schema=STRUCTURED_PARTIAL,
                )
                audit.record(idx, ok=True, ms=now()-t0, attempt=attempt)
                return Outcome(idx=idx, ok=True, value=r)
            except (LLMError, ValidationError) as e:
                audit.record(idx, ok=False, err=str(e), attempt=attempt)
        return Outcome(idx=idx, ok=False)

    partials = parallel_for(enumerate(chunks)) do |i, c|
        if now() > deadline: return Outcome(idx=i, ok=False, err="budget")
        return map_one(c, i)
    end

    successes = [p for p in partials if p.ok]
    if len(successes) < len(chunks) * MIN_MAP_RATIO:
        signal_replan(task, reason="too few successful map chunks")
        return Result(ok=False, audit=audit)

    aggregate = llm.reduce(task=task, partials=[s.value for s in successes],
                           protocol="dependencies + claims + sources")

    # Conflict-resolution pass; if it cannot reach convergence, replan.
    for round in range(MAX_RESOLVE_ROUNDS):
        calibrated = llm.calibrate(aggregate=aggregate,
                                   partials=[s.value for s in successes],
                                   resolve_conflicts=True)
        if calibrated.unresolved_conflicts == 0:
            return Result(ok=True, value=calibrated, audit=audit)
        aggregate = calibrated
    signal_replan(task, reason="conflicts did not converge")
    return Result(ok=False, audit=audit)

# Why this works: per-chunk retries contain transient map failures; the
# audit records which chunks contributed; partial reduce tolerates a
# bounded miss-rate; conflicts that refuse to converge become a replan
# signal instead of low-quality output.
# Related: see `step-budget`, `replan-on-failure`, `iteration-node`.

# Generator interface: pure function over (node, history, K) -> candidates.
# Search policy is intentionally NOT inside the generator.

def multi_path_generator(node, history, K):
    # Ask the model for K distinct next-step proposals at this node.
    candidates = llm.propose_next_steps(
        node    = node,
        history = history,
        k       = K,
        schema  = STEP_SCHEMA,
        diverse = True,                  # encourage spread, not duplicates
    )
    return dedupe(candidates)

# Swappable search policies consume the generator's output.
def tree_of_thoughts_search(root, generator, K=5, depth=4):
    frontier = [root]
    for _ in range(depth):
        next_frontier = []
        for node in frontier:
            candidates = generator(node, history_of(node), K)
            for c in candidates:
                child = expand(node, c)
                next_frontier.append(child)
        frontier = keep_best(next_frontier, value_fn=evaluate, n=BEAM)
    return best_leaf(frontier)

def beam_search(root, generator, K=5, beam=3, depth=4):
    frontier = [(0.0, root)]
    for _ in range(depth):
        candidates = []
        for score, node in frontier:
            for c in generator(node, history_of(node), K):
                candidates.append((score + evaluate(c), expand(node, c)))
        frontier = sorted(candidates, reverse=True)[:beam]
    return best_leaf([n for _, n in frontier])

# Why this works: separating generation from search lets each be tuned
# independently. The same generator drives tree-of-thoughts, LATS, beam,
# or MCTS without rewriting the proposal logic.
# Related: see `tree-of-thoughts`, `lats`, `single-path-plan-generator`.

function outer(goal):
    plan = outer_agent.decompose(goal)      # subtasks with milestones
    global_state = {goal: goal, done: []}

    for sub in plan:
        interrupt = Channel()
        result = inner(sub, interrupt)      # may signal mid-run
        global_state.done.append((sub, result))

        if outer_agent.should_replan(global_state):
            plan = outer_agent.replan(global_state)

    return outer_agent.summarise(global_state)

function inner(subtask, interrupt):
    messages = [system_for(subtask)]
    for step in 1..MAX_STEPS:
        if interrupt.signalled():
            return Result(ok=False, reason="outer asked to stop")
        reply = llm.generate(messages=messages, tools=tools_for(subtask))
        messages.append(reply)
        if not reply.tool_calls:
            return Result(ok=True, value=reply.content)
        for call in reply.tool_calls:
            messages.append(tool_result(call.id, dispatch(call)))
    return Result(ok=False, reason="step budget")

function outer_prod(goal, budget):
    audit = AuditLog()
    plan = outer_agent.decompose(goal)
    global_state = {goal: goal, done: []}
    outer_step = 0

    for sub in plan:
        outer_step += 1
        if outer_step > budget.outer_steps:
            audit.record("outer_budget_exhausted"); break

        interrupt = Channel()
        deadline_for_sub = sub.estimated_ms * SAFETY_FACTOR
        watchdog = schedule(deadline_for_sub, () => interrupt.signal("watchdog"))

        t0 = now()
        result = inner_prod(sub, interrupt, audit, budget.inner_steps)
        watchdog.cancel()
        audit.record("subtask", sub.id, ms=now()-t0, ok=result.ok)

        global_state.done.append((sub, result))

        # Milestone check: outer sees ONLY structured result + cumulative state.
        if missed_milestone(sub, result, global_state):
            audit.record("replan_trigger", sub.id, reason="milestone miss")
            plan = outer_agent.replan(global_state)
            continue

        if outer_agent.should_replan(global_state):
            plan = outer_agent.replan(global_state)

    return outer_agent.summarise(global_state)

function inner_prod(subtask, interrupt, audit, max_steps):
    messages = [system_for(subtask)]
    for step in 1..max_steps:
        if interrupt.signalled():
            audit.record("inner_interrupted", subtask.id)
            return Result(ok=False, reason=interrupt.reason())
        reply = llm.generate(messages=messages, tools=tools_for(subtask))
        messages.append(reply)
        if not reply.tool_calls:
            return Result(ok=True, value=reply.content)
        for call in reply.tool_calls:
            messages.append(tool_result(call.id, dispatch(call)))
    return Result(ok=False, reason="inner step budget")

# Why this works: outer and inner budgets are explicit and independent;
# the interrupt channel + watchdog prevent runaway inner loops; milestone
# misses bubble up to the planner without rebuilding ReAct's per-step
# planner cost.
# Related: see `step-budget`, `replan-on-failure`, `planner-executor-observer`.

# outer-inner-agent-loop gives the two-loop SHAPE; planner-executor-observer
# gives a third role (Observer) that is the only one allowed to call
# loop/respond/replan. Composed: Observer reads cumulative subtask results
# and tells Outer what to do next.

function outer_with_observer(goal):
    plan = planner.run(goal)
    global_state = {goal: goal, done: []}

    while True:
        next_sub = plan.next(global_state.done)
        if next_sub is None:
            verdict = observer.judge(goal, plan, global_state.done)
            if verdict == "respond":
                return planner.summarise(goal, global_state.done)
            if verdict == "replan":
                plan = planner.run(goal, context=global_state.done)
                continue

        # Inner loop runs ReAct on ONE subtask, reports structured result.
        interrupt = Channel()
        result = inner_react(next_sub, interrupt)
        global_state.done.append((next_sub, result))

        # Observer reads CUMULATIVE state, not just the latest subtask.
        verdict = observer.judge(goal, plan, global_state.done)
        if verdict == "replan":
            plan = planner.run(goal, context=global_state.done)
            interrupt.signal("observer requested replan")  # cancel in-flight
        elif verdict == "respond":
            return planner.summarise(goal, global_state.done)
        # else: continue with current plan

# Why this works: the outer loop dispatches; the Observer judges; the
# inner loop acts. Three responsibilities, three roles. The Observer can
# interrupt mid-run via the channel the outer-inner shape already provides.
# Related: see `planner-executor-observer`, `replan-on-failure`.

class AgentProd:
    def __init__(self, id, neighbours, audit):
        self.id, self.neighbours, self.audit = id, neighbours, audit
        self.local_plan = []
        self.pgp        = PartialGlobalPlan()
        self.gossip_budget = TokenBucket(rate=GOSSIP_PER_SEC)
        self.inconsistent_cycles = 0

    def planning_tick(self):
        t0 = now()
        self.local_plan = planner.local(self.id, self.pgp, world_view(self.id))
        fragment = self.pgp.derive_fragment_from(self.local_plan)
        fragment.version = (self.id, now_logical())   # version vector
        for n in self.neighbours:
            if self.gossip_budget.try_take():
                send(n, "plan_fragment", fragment)
                self.audit.record("gossip", from_=self.id, to=n,
                                  ver=fragment.version)
            else:
                self.audit.record("gossip_dropped", from_=self.id, to=n)
        self.audit.record("plan_tick", id=self.id, ms=now()-t0)

    def on_message(self, sender, kind, payload):
        if kind == "plan_fragment":
            res = self.pgp.merge(sender, payload)
            self.audit.record("merge", sender, accepted=res.accepted,
                              conflicts=res.conflicts)
            if res.unresolved_conflict:
                self.inconsistent_cycles += 1
                if self.inconsistent_cycles > REPLAN_LIMIT:
                    signal_replan(self.id, reason="persistent PGP conflict")
            else:
                self.inconsistent_cycles = 0
            if res.accepted:
                schedule(self.planning_tick, in_=SHORT_DELAY)

# Why this works: version-vectored fragments give the merge a clear order;
# the gossip budget bounds per-edge traffic; persistent merge conflicts
# escalate to a replan rather than leaving the agent stuck in disagreement.
# Related: see `step-budget`, `replan-on-failure`, `distributed-constraint-optimization`.

function plan_and_execute(goal):
    plan = strong_llm.plan(goal)              # ordered list of steps
    log("plan", plan)                          # inspectable up front
    results = []

    for step in plan:
        try:
            result = cheap_llm.execute(step, context=results)
            results.append(result)
        except SurpriseOrFailure as exc:
            # ask the strong planner to repair, given partial progress
            plan = strong_llm.replan(goal, results, error=exc)
            return plan_and_execute_continue(plan, results)

    return cheap_llm.summarise(goal, results)

from pydantic import BaseModel, Field
from langchain.agents import create_agent
