def run(goal: str) -> list[str]:
    plan_result = planner.invoke(
        {"messages": [{"role": "user",
                       "content": f"Plan ordered steps to achieve: {goal}"}]}
    )
    plan: Plan = plan_result["structured_response"]
    results: list[str] = []
    for step in plan.steps:
        out = executor.invoke(
            {"messages": [{"role": "user", "content": step}]}
        )
        results.append(out["messages"][-1].content)
    return results


