function run(goal):
    plan = planner.run(goal)                # ordered steps
    results = []

    while true:
        if len(results) >= len(plan):
            verdict = observer.judge(goal, plan, results)
            if verdict == "respond":
                return executor.summarise(goal, results)
            if verdict == "replan":
                plan = planner.run(goal, context=results)
                continue

        step = plan[len(results)]
        outcome = executor.run(step, context=results)
        results.append(outcome)

        # observer reads cumulative state, not just the latest step
        verdict = observer.judge(goal, plan, results)
        if verdict == "replan":
            plan = planner.run(goal, context=results)
        if verdict == "respond":
            return executor.summarise(goal, results)

function run_prod(goal, budget):
    audit = AuditLog()
    plan = planner.run(goal)
    audit.record("plan", plan)
    results = []
    replan_count = 0
    consecutive_dissent = 0

    while True:
        if len(results) >= len(plan):
            verdict = observer.judge(goal, plan, results)
            audit.record("observer", verdict, stage="end_of_plan")
            if verdict == "respond":
                return executor.summarise(goal, results)
            if verdict == "replan":
                if replan_count >= MAX_REPLANS:
                    audit.record("abort_replan_thrash")
                    return Result(ok=False, reason="too many replans")
                replan_count += 1
                plan = planner.run(goal, context=results)
                audit.record("plan", plan, replan=replan_count)
                continue

        step = plan[len(results)]
        if budget.exhausted(): return Result(ok=False, reason="budget")
        t0 = now()
        outcome = executor.run(step, context=results)
        results.append(outcome)
        audit.record("step", step.id, ms=now()-t0, ok=outcome.ok)

        verdict = observer.judge(goal, plan, results)
        audit.record("observer", verdict, after_step=step.id)

        if verdict == "replan":
            consecutive_dissent += 1
            if consecutive_dissent >= DISSENT_LIMIT:
                return Result(ok=False, reason="observer keeps dissenting")
            replan_count += 1
            plan = planner.run(goal, context=results)
        else:
            consecutive_dissent = 0
        if verdict == "respond":
            return executor.summarise(goal, results)

# Why this works: replan throttling prevents the planner/observer from
# ping-ponging forever; the audit records every observer verdict so post-
# hoc analysis can show whether the observer or the planner was the
# bottleneck; persistent dissent fails the run instead of looping silently.
# Related: see `step-budget`, `replan-on-failure`.

function harness(goal):
    feature_list = planner.run(goal)        # ordered chunks + criteria
    artefact = empty_artefact()

    for chunk in feature_list.chunks:
        attempts = 0
        while attempts < MAX_RETRIES:
            # Generator runs in a fresh context: feature_list,
            # current artefact, and the target chunk only.
            artefact = generator.run(
                feature_list=feature_list,
                artefact=artefact,
                chunk=chunk,
            )
            # Evaluator runs in its own fresh context: artefact +
            # rubric only. It does not see the generator's trace.
            verdict = evaluator.run(
                artefact=artefact,
                rubric=feature_list.rubric,
            )
            if verdict.pass_:
                break
            attempts += 1
        if not verdict.pass_:
            return Result(ok=false, chunk=chunk, findings=verdict.findings)

    return Result(ok=true, artefact=artefact)

function proactive_goal_creator(user_prompt, session):
    # explicit notification — low false-positive rate
    if session.consent.allows_capture():
        notify_user("capturing context: screen + camera")

    raw = {}
    if session.devices.camera:
        raw.gestures = camera.snapshot_and_classify()
    if session.devices.screen:
        raw.screen = screen.snapshot_and_ocr()
    if session.devices.mic:
        raw.audio_summary = mic.recent_window_summary()
    if session.devices.sensors:
        raw.environment = sensors.read()

    engineered = context_engineer.filter_and_redact(raw)

    refined = llm.fuse(
        prompt=user_prompt,
        multimodal_context=engineered,
        schema=GOAL_SCHEMA,
    )
    return planner.start(refined)

def proactive_goal_creator_prod(user_prompt, session, audit):
    if session.consent.disabled():
        return passive_goal_creator(user_prompt, session.id)

    notify_user("capturing context: " +
                ", ".join(session.devices.allowed_list()))
    audit.record("capture_start", devices=session.devices.allowed_list())

    raw = {}
    for device in session.devices.allowed_list():
        t0 = now()
        try:
            raw[device] = with_timeout(SENSOR_TIMEOUT,
                                       lambda: capture(device))
            audit.record("capture_ok", device, ms=now()-t0)
        except (Timeout, SensorError) as e:
            audit.record("capture_fail", device, err=str(e))

    engineered = context_engineer.filter_and_redact(raw)
    audit.record("engineered", kept=engineered.kept_keys(),
                 dropped=engineered.dropped_keys())

    refined = llm.fuse(
        prompt=user_prompt,
        multimodal_context=engineered,
        schema=GOAL_SCHEMA,
    )
    audit.record("fused", confidence=refined.confidence)

    if refined.confidence < FUSION_FLOOR:
        # Replan: fall back to passive (prompt-only) refinement.
        audit.record("fallback_to_passive", reason="low fusion confidence")
        return passive_goal_creator(user_prompt, session.id)

    if refined.contradicts(user_prompt):
        # Don't act on a contradiction silently — ask the user.
        audit.record("contradiction", typed=user_prompt, fused=refined)
        return ask_user_to_resolve(user_prompt, refined)

    return planner.start(refined)

# Why this works: every sensor capture is audited and consent-gated;
# low-confidence fusions fall back to the passive path rather than acting
# on hallucinated multimodal signal; contradictions between what the user
# typed and what was inferred are surfaced rather than silently overridden.
# Related: see `passive-goal-creator`, `input-output-guardrails`.

def decomposer_agent(question):
    # Explicit role: enumerate INDEPENDENT leaf sub-queries that, together,
    # would answer the user's question. NOT an ordered plan — leaves.
    return llm.decompose(
        question = question,
        schema   = LEAVES_SCHEMA,
        rules    = "Each leaf must be answerable without the others.",
    )

def answerer_agent(leaf):
    # Each leaf goes through the same answering pipeline (RAG, tools, etc).
    return llm.answer(leaf, context=retriever.search(leaf))

def aggregator_agent(question, leaf_answers):
    return llm.compose(
        question     = question,
        leaf_answers = leaf_answers,
        rules        = "Resolve conflicts; cite which leaf each claim came from.",
    )

def query_decomposition(question):
    leaves = decomposer_agent(question)

    # Leaves are independent -> run in parallel.
    leaf_answers = parallel_map(answerer_agent, leaves)

    return aggregator_agent(question, leaf_answers)

# Distinct from Plan-and-Execute: P&E plans ORDERED actions. This pattern
# produces EQUIVALENT leaves that fan out and rejoin.

# Why this works: multi-part questions get one prompt per concern instead of
# one overloaded prompt; aggregation surfaces conflicts the monolithic
# version would silently average over.
# Related: see `self-ask`, `map-reduce`, `clone-fan-out-research`.

MAX_LEAVES = 12

def query_decomposition_prod(question, budget):
    audit = AuditLog()
    leaves = decomposer_agent(question)
    if len(leaves) > MAX_LEAVES:
        audit.record("leaves_truncated", original=len(leaves), kept=MAX_LEAVES)
        leaves = pick_top_leaves(leaves, MAX_LEAVES)
    audit.record("leaves", leaves)

    def answer_one(leaf):
        t0 = now()
        for attempt in range(LEAF_RETRIES + 1):
            try:
                r = with_timeout(LEAF_TIMEOUT, lambda: answerer_agent(leaf))
                audit.record("leaf_ok", leaf.id, attempt=attempt, ms=now()-t0)
                return LeafResult(leaf=leaf, ok=True, value=r)
            except (Timeout, ToolError) as e:
                audit.record("leaf_fail", leaf.id, attempt=attempt, err=str(e))
        return LeafResult(leaf=leaf, ok=False)

    leaf_answers = parallel_map(answer_one, leaves)
    successes = [r for r in leaf_answers if r.ok]
    if len(successes) < len(leaves) * MIN_LEAF_RATIO:
        signal_replan(question, reason="too few leaf answers")
        return Result(ok=False, audit=audit)

    agg = aggregator_agent(question, successes)
    audit.record("aggregate", used_leaves=[r.leaf.id for r in successes],
                 conflicts=agg.conflicts)

    # If the aggregator reports gaps, do ONE replan-decompose for the gap.
    if agg.has_gaps:
        gap_leaves = decomposer_agent.fill_gaps(question, agg.gaps)
        extra = parallel_map(answer_one, gap_leaves)
        agg = aggregator_agent(question, successes + extra)

    return Result(ok=True, value=agg, audit=audit)

# Why this works: bounded leaf count keeps cost predictable; per-leaf
# retries contain transient failure; the aggregator's gap detection
# triggers a narrow replan instead of returning a partial answer.
# Related: see `step-budget`, `replan-on-failure`, `clone-fan-out-research`.

function react(question, tools, max_steps):
    messages = [system_prompt, user(question)]
    for step in 1..max_steps:
        reply = llm.generate(messages=messages, tools=tools)
        messages.append(reply)            # records the Thought

        if not reply.tool_calls:
            return reply.content          # agent decided to answer

        call = reply.tool_calls[0]        # one tool call per step
        observation = dispatch(call.name, call.args)
        messages.append(tool_result(call.id, observation))
        # next iteration: model reasons over the fresh observation

    return abort("step budget exhausted")

