function execute_with_replan(goal):
    plan = planner.run(goal)
    progress = []

    while plan.has_more(progress):
        step = plan.next(progress)
        try:
            obs = executor.run(step)
            if observer.dissents(step, obs):
                raise ReplanTrigger("observer dissent", obs)
            if surprising(obs, step.expected):
                raise ReplanTrigger("unexpected observation", obs)
            progress.append((step, obs))
        except (ToolError, ReplanTrigger) as exc:
            # preserve compatible partial progress
            keep = [(s, o) for (s, o) in progress
                    if plan.still_valid(s)]
            plan = planner.run(
                goal,
                progress=keep,
                failure=exc,
            )
            progress = keep

    return executor.summarise(goal, progress)

from datetime import timedelta
from temporalio import workflow
from temporalio.common import RetryPolicy
from temporalio.exceptions import ApplicationError


@workflow.defn
class ReplanOnFailure:
    @workflow.run
    async def run(self, goal: str) -> str:
        plan = await workflow.execute_activity(
            "plan", goal,
            start_to_close_timeout=timedelta(minutes=2),
        )
        progress: list[dict] = []

        for step in plan:
            try:
                obs = await workflow.execute_activity(
                    "execute_step", {"step": step, "progress": progress},
                    start_to_close_timeout=timedelta(minutes=5),
                    retry_policy=RetryPolicy(
                        initial_interval=timedelta(seconds=2),
                        maximum_attempts=3,
                        # non_retryable: planner-relevant signals
                        non_retryable_error_types=["ReplanTrigger"],
                    ),
                )
                progress.append({"step": step, "obs": obs})
            except ApplicationError as exc:
                if exc.type != "ReplanTrigger":
                    raise
                # replan with failure context; keep compatible progress
                plan = await workflow.execute_activity(
                    "plan",
                    {"goal": goal, "progress": progress, "failure": str(exc)},
                    start_to_close_timeout=timedelta(minutes=2),
                )
        return await workflow.execute_activity(
            "summarise", {"goal": goal, "progress": progress},
            start_to_close_timeout=timedelta(minutes=2),
        )

# planner-executor-observer separates planning, acting, and judging.
# replan-on-failure uses TRIGGERS, but lets only the Observer issue them,
# so the executor cannot mask failures or decide policy on its own.

function run_with_observer_replan(goal):
    plan     = planner.run(goal)
    progress = []
    replans  = 0

    while True:
        if all_done(plan, progress):
            verdict = observer.judge(goal, plan, progress)
            if verdict == "respond":
                return executor.summarise(goal, progress)
            if verdict == "replan":
                replans += 1
                if replans > MAX_REPLANS: return Result(ok=False, reason="thrash")
                plan = planner.run(goal, context=progress); continue

        step = next_step(plan, progress)
        try:
            obs = executor.run(step)
        except ToolError as e:
            # Executor reports the error UP; it does NOT replan.
            obs = ErrorObservation(step=step, err=str(e))

        progress.append((step, obs))

        # Observer is the sole replan authority.
        verdict = observer.judge(goal, plan, progress)
        if verdict == "replan":
            replans += 1
            if replans > MAX_REPLANS: return Result(ok=False, reason="thrash")
            # Preserve compatible partial progress.
            keep = [(s, o) for (s, o) in progress
                    if isinstance(o, ErrorObservation) is False
                    and plan.still_valid(s)]
            plan = planner.run(goal, progress=keep)
            progress = keep
        elif verdict == "respond":
            return executor.summarise(goal, progress)

# Why this works: separating WHO decides to replan from WHO executes
# prevents the executor from masking errors as "I'll try again" forever;
# the Observer reads cumulative state to decide whether a fresh plan is
# warranted, with a hard replan cap to break thrash.
# Related: see `planner-executor-observer`, `step-budget`.

function rewoo(query):
    # Planner emits a DAG: each step references prior outputs as #t1 etc.
    # The planner does NOT see any tool observations.
    plan = planner.run(
        query,
        schema="""
        steps:
          - id: t1
            tool: ToolA
            args: {x: <literal>}
          - id: t2
            tool: ToolB
            args: {input: "#t1"}
        """,
    )

    # Worker executes in dependency order; substitutes #t_i references.
    results = {}
    for step in topological_order(plan.steps):
        args = substitute(step.args, results)   # #t1 -> results[t1]
        results[step.id] = run_tool(step.tool, args)

    # Solver sees the resolved trace and produces the final answer.
    return solver.run(query, plan=plan, results=results)

function rewoo_prod(query, budget):
    audit = AuditLog()
    plan = planner.run(query, schema=REWOO_SCHEMA)
    audit.record("plan", plan)

    results = {}
    deadline = now() + budget.total_ms

    for step in topological_order(plan.steps):
        if now() > deadline:
            audit.record("abort_deadline", step.id)
            results[step.id] = MissingValue(reason="deadline")
            continue

        args = substitute(step.args, results)
        for attempt in range(PER_STEP_RETRIES + 1):
            t0 = now()
            try:
                results[step.id] = with_timeout(STEP_TIMEOUT,
                                                lambda: run_tool(step.tool, args))
                audit.record("step_ok", step.id, attempt=attempt, ms=now()-t0)
                break
            except (Timeout, ToolError) as e:
                audit.record("step_fail", step.id, attempt=attempt, err=str(e))
        else:
            if step.id in plan.critical_path:
                # Replan from the planner; observations stay OUT of its prompt.
                plan = planner.run(
                    query,
                    prior_failures=audit.failures_summary(),
                    schema=REWOO_SCHEMA,
                )
                audit.record("replan_critical", step.id)
                return rewoo_prod(query, budget)   # restart with new plan
            results[step.id] = MissingValue(reason="max retries")

    # Solver sees resolved trace; tolerates MissingValue gracefully.
    return solver.run(query, plan=plan, results=results, audit=audit)

# Why this works: critical-path failures escalate to a replanner that
# still never sees raw observations (preserving ReWOO's token-cost win);
# non-critical-path failures pass MissingValue to the solver which the
# solver knows how to handle. Every step is audited end-to-end.
# Related: see `step-budget`, `replan-on-failure`, `llm-compiler`.

# ReWOO produces a DAG of placeholder-referenced steps; llm-compiler is a
# concurrent dispatcher for exactly that DAG shape. Composing them keeps
# ReWOO's planner-never-sees-observations property AND collapses end-to-
# end latency to the longest dependency chain.

function rewoo_concurrent(query):
    # ReWOO planner: builds the DAG with variable references (#t1, #t2).
    plan = planner.run(query, schema=REWOO_SCHEMA)

    # LLMCompiler-style task-fetching: dispatch steps as deps resolve.
    results = {}
    pending = {n.id: set(n.deps) for n in plan.steps}
    pool = ConcurrencyPool(MAX_PARALLEL)

    while pending or pool.in_flight():
        for n in plan.steps:
            if n.id in pending and not pending[n.id]:
                args = substitute(n.args, results)
                pool.submit(n.id, () => run_tool(n.tool, args))
                del pending[n.id]

        done_id, value = pool.wait_one()
        results[done_id] = value
        for nid in pending:
            pending[nid].discard(done_id)

    # ReWOO solver: reads resolved trace. Planner STILL never saw observations.
    return solver.run(query, plan=plan, results=results)

# Why this works: ReWOO's win is token-cost (planner ignores observations);
# LLMCompiler's win is latency (overlap independent steps). The DAG shape
# is common, so composing them gives BOTH wins on the same execution.
# Related: see `llm-compiler`, `parallel-tool-calls`.

