def reducer(state, event):
    # Pure: no I/O, no clocks. Side effects returned as descriptors.
    if event.kind == "user_message":
        new = state.with_message(event.text)
        return new, [Effect("llm_call", id=event.id+"_llm",
                            prompt=build_prompt(new))]
    if event.kind == "llm_reply":
        new = state.with_reply(event.reply)
        fx = [Effect("tool", id=event.id+":"+c.id,
                     name=c.name, args=c.args)
              for c in event.reply.tool_calls]
        return new, fx
    if event.kind == "tool_result":
        new = state.with_tool_result(event.id, event.value)
        return new, [Effect("llm_call", id=event.id+"_llm",
                            prompt=build_prompt(new))]
    return state, []

class RuntimeProd:
    def __init__(self, log, audit):
        self.log, self.audit = log, audit
        self.seen_effect_ids = set()              # idempotency

    def handle(self, event):
        state = self.replay()
        new_state, fx = reducer(state, event)
        self.log.append(event)
        self.audit.record("event", event.kind, event.id)
        for e in fx:
            if e.id in self.seen_effect_ids: continue
            self.seen_effect_ids.add(e.id)
            for attempt in range(EFFECT_RETRIES + 1):
                try:
                    self.dispatch(e); break
                except TransientError:
                    sleep(backoff(attempt))
            else:
                self.audit.record("effect_failed", e.id)
                self.handle(Event("effect_failed", effect_id=e.id))

    def replay(self, until=None):
        state = INITIAL_STATE
        prev_hash = b""
        for e in self.log.iter(until=until):
            state, _ = reducer(state, e)
            h = state.hash()
            if e.expected_state_hash and e.expected_state_hash != h:
                # Replay divergence — log slice is corrupt or reducer changed.
                signal_replan("replay divergence", at_event=e.id)
                raise ReplayDivergence(e.id)
            prev_hash = h
        return state

# Why this works: effects carry idempotency ids so retried dispatches
# don't double-fire; log replay checks expected state hashes so a
# reducer-version change or a corrupt log slice surfaces as a divergence
# rather than silent drift. The audit logs every event and every dispatch.
# Related: see `durable-workflow-snapshot`, `step-budget`.

function todo_driven_agent(goal, sandbox):
    # 1) author the plan as a file in the sandbox
    if not sandbox.exists("todo.md"):
        sandbox.write("todo.md", agent.draft_plan(goal))

    while true:
        todo = sandbox.read("todo.md")
        items = parse_checklist(todo)
        unticked = [i for i in items if not i.done]
        if not unticked:
            return agent.summarise(goal, todo)

        next_item = unticked[0]

        # re-inject the unticked tail into the prompt
        outcome = agent.run_one_turn(
            goal=goal,
            current_item=next_item,
            remaining=unticked,
        )

        # update the file: tick, add follow-ups, drop dead-ends
        todo = update_checklist(todo, next_item, outcome)
        sandbox.write("todo.md", todo)

graph:
  nodes:
    - id: start
      type: Start
      outputs: {message: string}

    - id: classify
      type: LLM
      model: gpt-4o-mini
      inputs: {message: "$start.message"}
      outputs: {intent: string}

    - id: route
      type: Conditional
      cases:
        - when: "intent == 'billing'"
          goto: billing_agent
        - default: tech_agent

    - id: billing_agent
      type: Agent
      tools: [lookup_invoice]
      outputs: {reply: string}

    - id: tech_agent
      type: Agent
      tools: [search_kb]
      outputs: {reply: string}

    - id: end
      type: End
      inputs: {reply: "$billing_agent.reply | $tech_agent.reply"}

edges:
  - {from: start,         to: classify}
  - {from: classify,      to: route}
  - {from: route,         to: [billing_agent, tech_agent]}
  - {from: billing_agent, to: end}
  - {from: tech_agent,    to: end}

function execute_graph_prod(graph, inputs, audit):
    validate_graph(graph)                          # types + connectivity
    visited = []
    values  = {"$inputs": inputs}
    deadline = now() + GRAPH_BUDGET_MS

    node = graph.start
    while not isinstance(node, EndNode):
        if now() > deadline:
            audit.record("abort_deadline", at=node.id); break

        # Schema validation at the edge: every input slot must have a value.
        inp = resolve_inputs(node, values)
        ok, errs = node.input_schema.validate(inp)
        if not ok:
            audit.record("schema_violation", node=node.id, errs=errs)
            return Result(ok=False, audit=audit)

        t0 = now()
        try:
            out = with_timeout(NODE_TIMEOUT,
                               lambda: node.execute(inp))
            audit.record("node_ok", node.id, ms=now()-t0)
        except (Timeout, NodeError) as e:
            audit.record("node_fail", node.id, err=str(e))
            return Result(ok=False, audit=audit)

        values["$" + node.id] = out
        visited.append(node.id)

        next_id = graph.route_from(node, out)
        if next_id is None:
            # Conditional with no matching case — replan-from-graph.
            audit.record("dead_end", at=node.id, output=out)
            new_graph = graph_planner.repair(graph, dead_end=node.id,
                                             output=out, audit=audit)
            if new_graph is None:
                return Result(ok=False, audit=audit)
            graph = new_graph
            next_id = graph.route_from(node, out)
        node = graph.node(next_id)
        audit.record("edge", from_=visited[-1], to=node.id)

    return Result(ok=True, value=values, audit=audit)

# Why this works: schema validation at each edge catches typed-input
# mismatches before they become runtime errors; per-node timeouts contain
# slow tools; dead-end conditionals trigger a structured graph repair
# rather than crashing the canvas.
# Related: see `step-budget`, `replan-on-failure`, `iteration-node`.
